using System.ComponentModel;
using System.Text.Json;
using ModelContextProtocol.Server;

namespace ApiMcpServer.Tools;

/// <summary>
/// MCP tools that wrap a REST API via HttpClient.
/// Non-static class — the SDK creates an instance per call, injecting DI services via the constructor.
/// </summary>
[McpServerToolType]
public class WeatherApiTools(HttpClient httpClient, ILogger<WeatherApiTools> logger)
{
    private static readonly JsonSerializerOptions JsonOptions = new() { WriteIndented = true };

    [McpServerTool, Description("Get the current weather forecast for a city.")]
    public async Task<string> GetForecast(
        [Description("City name, e.g. 'Seattle'")] string city,
        [Description("Number of forecast days (1-5)")] int days = 3,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Fetching {Days}-day forecast for {City}", days, city);

        var response = await httpClient.GetAsync(
            $"/v1/forecast?city={Uri.EscapeDataString(city)}&days={days}",
            cancellationToken);

        response.EnsureSuccessStatusCode();
        var json = await response.Content.ReadAsStringAsync(cancellationToken);
        return json;
    }

    [McpServerTool, Description("Search for cities matching a query string.")]
    public async Task<string> SearchCities(
        [Description("Partial city name to search for")] string query,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Searching cities matching '{Query}'", query);

        var response = await httpClient.GetAsync(
            $"/v1/cities?q={Uri.EscapeDataString(query)}",
            cancellationToken);

        response.EnsureSuccessStatusCode();
        var json = await response.Content.ReadAsStringAsync(cancellationToken);
        return json;
    }

    [McpServerTool(ReadOnly = true), Description("Get current conditions for a specific location by coordinates.")]
    public async Task<string> GetCurrentConditions(
        [Description("Latitude of the location")] double latitude,
        [Description("Longitude of the location")] double longitude,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Getting conditions at ({Lat}, {Lon})", latitude, longitude);

        var response = await httpClient.GetAsync(
            $"/v1/current?lat={latitude}&lon={longitude}",
            cancellationToken);

        response.EnsureSuccessStatusCode();
        var content = await response.Content.ReadFromJsonAsync<JsonElement>(cancellationToken);
        return JsonSerializer.Serialize(content, JsonOptions);
    }
}

