 using Microsoft.Extensions.DependencyInjection;
 using Microsoft.Extensions.Hosting;
 using Microsoft.Extensions.Logging;

 var builder = Host.CreateApplicationBuilder(args);

 // CRITICAL: route all logs to stderr — stdout is reserved for MCP JSON-RPC messages.
 builder.Logging.AddConsole(o => o.LogToStandardErrorThreshold = LogLevel.Trace);

 // Register a typed HttpClient that the SDK will inject into WeatherApiTools via constructor.
 builder.Services.AddHttpClient<ApiMcpServer.Tools.WeatherApiTools>(client =>
 {
     client.BaseAddress = new Uri("https://api.weatherapi.example.com");
     client.DefaultRequestHeaders.Add("Accept", "application/json");
 });

 builder.Services
     .AddMcpServer()
     .WithStdioServerTransport()
     .WithToolsFromAssembly();   // discovers all [McpServerToolType] classes in this assembly

 await builder.Build().RunAsync();
